import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './TopWorstSellers.css';
import Optionbar from './Optionbar';
import {
    segmentOptions,
    locationOptions,
    seasonOptions,
    highlightOptions
} from './Icons/optionbarOptions';

// Helper to get all IDs as Set
const makeSet = arr => new Set(arr.map(o => o.id));

const TopWorstSellers = () => {
    const [searchTerm, setSearchTerm] = useState('');
    const [sortOrder, setSortOrder] = useState('top');
    const [items, setItems] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);

    // Initialize filters with all options checked
    const [filters, setFilters] = useState({
        segments:    makeSet(segmentOptions),
        highlights:  makeSet(highlightOptions),
        seasons:     makeSet(seasonOptions),
        locations:   makeSet(locationOptions)
    });

    useEffect(() => {
        const fetchSales = async () => {
            setLoading(true);
            try {
                const params = {};
                // Only include non-empty filter sets
                Object.entries(filters).forEach(([key, set]) => {
                    if (set.size && set.size !== 0) {
                        params[key] = Array.from(set).join(',');
                    }
                });
                const res = await axios.get('http://localhost:3007/api/sales', {
                    params,
                    withCredentials: true
                });
                setItems(
                    res.data.map(({ item_name, sold_count }) => ({ name: item_name, count: sold_count }))
                );
            } catch (err) {
                console.error(err);
                setError('Kon verkoopcijfers niet laden');
            } finally {
                setLoading(false);
            }
        };
        fetchSales();
    }, [filters]);

    if (loading) return <p>Loading…</p>;
    if (error) return <p className="error">{error}</p>;

    const sorted = [...items].sort((a, b) =>
        sortOrder === 'top' ? b.count - a.count : a.count - b.count
    );

    const visible = sorted.filter(item =>
        item.name.toLowerCase().includes(searchTerm.toLowerCase())
    );

    return (
        <div className="top-worst-container">
            <Optionbar filters={filters} onChange={setFilters} />
            <div className="centre-content">
                <div className="segment-section">
                    <h2 className="section-title">Top & Worst</h2>
                </div>
                <div className="items-section">
                    <div className="list-header">
                        <div className="header-title">
                            <p>Top & Worst</p>
                            <h2 className="section-title">Cocktail-items</h2>
                        </div>
                        <div className="section-order">
                            <span
                                className={`order-button ${sortOrder==='top'?'active':''}`}
                                onClick={()=>setSortOrder('top')}
                            >Top sellers ↑</span>
                            <span
                                className={`order-button ${sortOrder==='worst'?'active':''}`}
                                onClick={()=>setSortOrder('worst')}
                            >Worst sellers ↓</span>
                        </div>
                        <div className="search-bar">
                            <input
                                type="text"
                                placeholder="Search"
                                value={searchTerm}
                                onChange={e=>setSearchTerm(e.target.value)}
                            />
                        </div>
                    </div>
                    <ul className="items-list">
                        {visible.map((item,index)=>(
                            <li key={index} className="item">
                                <span>{index+1}. {item.name}</span>
                                <span className="item-count">{item.count} sold</span>
                            </li>
                        ))}
                    </ul>
                </div>
            </div>
        </div>
    );
};

export default TopWorstSellers;
